private boolean inOrderTraversal(TreeNode node, Set<Integer> visited) {
    if (node == null) {
        return true;
    }
    if (inOrderTraversal(node.left, visited)) {
        if (visited.contains(node.val)) {
            return true;
        }
        visited.add(node.val);
        return inOrderTraversal(node.right, visited);
    }
    return false;
