function findCentroids(dataPoints, k) {
    if (dataPoints.length === 0 || k <= 0) return [];

    // Initialize centroids randomly
    let centroids = [];
    for (let i = 0; i < k; i++) {
        centroids.push({
            x: Math.random() * 100,
            y: Math.random() * 100
        });
    }

    // Iterate until centroids stabilize
    let changed = true;
    while (changed) {
        changed = false;
        for (let i = 0; i < dataPoints.length; i++) {
            let closest = null;
            let minDistance = Infinity;
            for (let j = 0; j < k; j++) {
                let dx = dataPoints[i].x - centroids[j].x;
                let dy = dataPoints[i].y - centroids[j].y;
                let distance = Math.sqrt(dx * dx + dy * dy);
                if (distance < minDistance) {
                    minDistance = distance;
                    closest = j;
                }
            }
            if (i !== closest) {
                // Move the centroid
                centroids[closest] = {
                    x: dataPoints[i].x,
                    y: dataPoints[i].y
                };
                changed = true;
            }
        }
    }

    return centroids;
}
