fn find_all_scc(graph: &Vec<Vec<usize>>) -> Vec<Vec<usize>> {
    let n = graph.len();
    let mut visited = vec![false; n];
    let mut sccs = vec![];

    // To keep track of the current component being processed
    let mut current_component = VecDeque::new();
    let mut component = Vec::new();

    for node in 0..n {
        if !visited[node] {
            current_component.push_back(node);
            visited[node] = true;
            component.push(node);
            let mut stack = vec![node];
            let mut component_nodes = HashSet::new();

            while let Some(u) = stack.pop() {
                component_nodes.insert(u);
                for &v in &graph[u] {
                    if !visited[v] {
                        visited[v] = true;
                        stack.push(v);
                        current_component.push_back(v);
                        component.push(v);
                    }
                }
            }

            sccs.push(component_nodes.into_iter().collect());
        }
    }

    sccs
}
