struct interval *interval_insert(struct interval *root, int start, int end) {
    if (root == NULL) {
        return malloc(sizeof(struct interval));
    }

    if (start < root->start) {
        root->left = interval_insert(root->left, start, end);
    } else if (end > root->end) {
        root->right = interval_insert(root->right, start, end);
    } else {
        // Overlap detected, merge intervals
        if (start > root->start) {
            root->left = interval_insert(root->left, start, end);
        } else if (end < root->end) {
            root->right = interval_insert(root->right, start, end);
        }
    }

    // Merge intervals if necessary
    if (root->left && root->left->end >= start) {
        root->left->end = end;
    }
    if (root->right && root->right->start <= end) {
        root->right->start = start;
    }

