        for (int i = 0; i < n; i++) {
            dist[i] = INF;
        }
        dist[source] = 0;

        // Relax edges for n-1 times
        for (int i = 0; i < n - 1; i++) {
            boolean updated = false;
            for (int[] edge : adjacencyList.get(source)) {
                int u = edge[0];
                int v = edge[1];
                int weight = edge[2];
                if (dist[u] != INF && dist[v] > dist[u] + weight) {
                    dist[v] = dist[u] + weight;
                    pred[v] = u;
                    updated = true;
