public class Solution {
    public String findLongestRepeatedSubstring(String text) {
        if (text == null || text.isEmpty()) {
            return "";
        }

        int n = text.length();
        int[] suffixArray = new int[n];
        int[] lcp = new int[n];

        // Build suffix array
        for (int i = 0; i < n; i++) {
            suffixArray[i] = i;
        }

        // Sort suffix array based on the suffix starting at each index
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - i - 1; j++) {
                int k = suffixArray[j];
                int l = suffixArray[j + 1];
                if (text.substring(k).compareTo(text.substring(l)) > 0) {
                    int temp = suffixArray[j];
                    suffixArray[j] = suffixArray[j + 1];
                    suffixArray[j + 1] = temp;
                }
            }
        }

        // Compute LCP array
        for (int i = 0; i < n - 1; i++) {
            int j = suffixArray[i];
            int k = suffixArray[i + 1];
            int len = 0;
            while (j + len < n && k + len < n && text.charAt(j + len) == text.charAt(k + len)) {
                len++;
            }
            lcp[i] = len;
        }

        // Find the maximum LCP value
        int maxLcp = 0;
        for (int i = 0; i < n - 1; i++) {
            if (lcp[i] > maxLcp) {
                maxLcp = lcp[i];
            }
        }

        // Find the longest repeated substring
        int start = 0;
        for (int i = 0; i < n - 1; i++) {
            if (lcp[i] == maxLcp) {
                start = suffixArray[i];
                break;
            }
        }

        return text.substring(start, start + maxLcp);
    }
}
