void dijkstra(Graph* graph, int source, int* dist) {
    int V = graph->size;
    int* dist = (int*)malloc(V * sizeof(int));
    int* prev = (int*)malloc(V * sizeof(int));
    int* visited = (int*)malloc(V * sizeof(int));
    int* pq = (int*)malloc(V * sizeof(int));
    int pq_size = 0;
    int pq_index = 0;

    // Initialize distances and visited array
    for (int i = 0; i < V; i++) {
        dist[i] = INF;
        visited[i] = 0;
    }
    dist[source] = 0;

    // Priority queue (min-heap)
    // Using a simple array for priority queue (not a proper heap)
    // This is for simplicity, but not a proper heap implementation
    pq[pq_index] = source;
    pq_index++;

    while (pq_index > 0) {
        int u = pq[pq_index - 1];
        pq_index--;

        // If we have already found the shortest path to u
        if (visited[u]) continue;

        // Explore all neighbors of u
        for (int v = 0; v < graph->size; v++) {
            if (graph->adj[v] == u && !visited[v]) {
                int new_dist = dist[u] + 1;
                if (new_dist < dist[v]) {
                    dist[v] = new_dist;
                    prev[v] = u;
                    pq[pq_index] = v;
                    pq_index++;
                }
            }
        }
    }

    // Reconstruct the path (optional)
    // For this implementation, we just return the distances
    for (int i = 0; i < V; i++) {
        dist[i] = dist[i];
    }

    free(prev);
    free(visited);
    free(pq);
    free(dist);
}

