int substring_search(const char *text, const char *pattern) {
    int n = strlen(text);
    int m = strlen(pattern);
    if (m == 0 || n < m) return -1;

    int pi[ m ];  // Prefix function
    int i = 0, j = 0;

    // Compute prefix function
    while (j < m) {
        if (pattern[j] == pattern[i]) {
            i++;
            j++;
            pi[j] = i;
        } else if (i > 0) {
            i = pi[i - 1];
        } else {
            j++;
            pi[j] = 0;
