    while (i < n && j < m) {
        if (text[i] == pattern[j]) {
            i++;
            j++;
        } else {
            if (j > 0) {
                j = pi[j - 1];
            } else {
                i++;
            }
        }
    }

    if (j == m) {
        return i - m;
    } else {
