        // Generate Huffman Codes
        Map<Character, String> codeMap = new HashMap<>();
        Queue<Node> queue = new LinkedList<>();
        queue.offer(pq.poll());
        while (!queue.isEmpty()) {
            Node node = queue.poll();
            if (node.left != null) {
                codeMap.put(node.left.charValue(), node.code);
                queue.offer(node.left);
            }
            if (node.right != null) {
                codeMap.put(node.right.charValue(), node.code);
                queue.offer(node.right);
            }
        }

        // Compress data
        StringBuilder compressed = new StringBuilder();
        for (char c : input.toCharArray()) {
            compressed.append(codeMap.get(c));
        }

        return compressed.toString();
    }

    static class Node {
        char charValue;
        int freq;
        Node left;
        Node right;
        String code;

        Node(char c, int f) {
            this.charValue = c;
            this.freq = f;
            this.code = "";
        }
    }
