impl LinkedList {
    fn new() -> Self {
        LinkedList { head: None }
    }

    fn insert(&mut self, value: i32) {
        let mut current = self.head.clone();
        while let Some(node) = current {
            current = node.borrow().next.clone();
        }
        self.head = Some(Rc::new(RefCell::new(Node { value, next: None })));
        let mut node = RefCell::new(Node { value, next: None });
        current = Some(node);
        while let Some(next_node) = current.clone().borrow().next.clone() {
            current = next_node;
        }
        current.borrow_mut().next = Some(node);
    }

    fn merge_sort(&mut self) {
        if self.head.is_none() {
            return;
        }

        let head = self.head.clone().unwrap();
        let mut sorted_list = Self::split(&mut self, head);
        self.head = sorted_list.head;
    }

    fn split(&mut self, head: Option<Rc<RefCell<Node>>>) -> Self {
        if head.is_none() {
            return Self::new();
        }

        let mid = self.split_at_mid(head);
        let left = self.split(&mut self, mid);
        let right = self.split(&mut self, mid);

        Self::merge(left, right)
    }

    fn split_at_mid(&mut self, head: Option<Rc<RefCell<Node>>>) -> Option<Rc<RefCell<Node>>> {
        if head.is_none() {
            return None;
        }

        let mut current = head.clone();
        let mut count = 0;
        while let Some(node) = current {
            current = node.borrow().next.clone();
            count += 1;
        }

        let mid = count / 2;
        let mut current = head.clone();
        for _ in 0..mid {
            current = current.clone().borrow().next.clone();
        }

        let left = self.split(&mut self, current);
        let right = self.split(&mut self, current);

        Some(Rc::new(RefCell::new(Node { value: current.borrow().value, next: None })))
    }

    fn merge(mut left: LinkedList, mut right: LinkedList) -> LinkedList {
        let mut result = LinkedList::new();
        let mut left_ptr = left.head;
        let mut right_ptr = right.head;

        while left_ptr.is_some() && right_ptr.is_some() {
            let left_node = left_ptr.clone().unwrap().borrow();
            let right_node = right_ptr.clone().unwrap().borrow();

            if left_node.value <= right_node.value {
                result.insert(left_node.value);
                left_ptr = left_ptr.clone().unwrap().borrow().next.clone();
            } else {
                result.insert(right_node.value);
                right_ptr = right_ptr.clone().unwrap().borrow().next.clone();
            }
        }

        // Append remaining nodes
        while left_ptr.is_some() {
            let node = left_ptr.clone().unwrap().borrow();
            result.insert(node.value);
            left_ptr = node.borrow().next.clone();
        }

        while right_ptr.is_some() {
            let node = right_ptr.clone().unwrap().borrow();
            result.insert(node.value);
            right_ptr = node.borrow().next.clone();
        }

        result
    }
