pub fn union_find<'a, T: PartialEq + Clone + 'a> (
    elements: &'a [T],
    operations: Vec<(T, T)>,
) -> Vec<usize> {
    let n = elements.len();
    let mut parent: Vec<T> = (0..n).map(|i| elements[i]).collect();
    let mut rank: Vec<usize> = (0..n).map(|i| 0).collect();

    fn find(parent: &Vec<T>, x: T) -> T {
        if parent[x] != x {
            parent[x] = find(parent, parent[x]);
        }
        parent[x]
    }

    fn union(parent: &mut Vec<T>, rank: &mut Vec<usize>, x: T, y: T) {
        let x_root = find(parent, x);
        let y_root = find(parent, y);
        if x_root == y_root {
            return;
        }
        if rank[x_root] < rank[y_root] {
            parent[x_root] = y_root;
        } else if rank[x_root] > rank[y_root] {
            parent[y_root] = x_root;
        } else {
            parent[y_root] = x_root;
            rank[x_root] += 1;
        }
    }

    for (x, y) in operations {
        union(&mut parent, &mut rank, x, y);
    }

    let mut result = Vec::new();
    for i in 0..n {
        result.push(find(&parent, elements[i]));
    }
    result
}
